// 200 questions about admin.lume.uz (LUME Admin System).
// Each question has bilingual text (RU/UZ), 3-4 answer options, the index of
// the correct option, and an optional screenshot path (under /public/screenshots).
//
// The questions intentionally cover both surface-level UI knowledge (where
// things live, what colours/icons sections use) and deeper, more specific
// behavioural facts (KPIs shown on a page, columns in a table, the URL
// segment used by a section, what each section is for, etc.).

export type Question = {
  id: number;
  // category for analytics / future filters
  cat: string;
  // path to screenshot inside /public (omit leading slash)
  shot?: string;
  ru: { q: string; opts: string[] };
  uz: { q: string; opts: string[] };
  correct: number; // index 0..opts.length-1
};

// Helper to keep declaration tidy
const q = (
  id: number,
  cat: string,
  shot: string | undefined,
  ru: { q: string; opts: string[] },
  uz: { q: string; opts: string[] },
  correct: number,
): Question => ({ id, cat, shot, ru, uz, correct });

