// Sanity check at boot
if (QUESTIONS.length !== 200) {
  // We do NOT throw at runtime in production — surfaced only in dev.
  if (process.env.NODE_ENV !== 'production') {
    console.warn('[questions] expected 200 questions, got', QUESTIONS.length);
  }
}

export function getQuestionById(id: number): Question | undefined {
  return QUESTIONS.find((q) => q.id === id);
}

// Returns a public-facing version of the question without the correct index.
export function publicQuestion(qq: Question) {
  return {
    id: qq.id,
    cat: qq.cat,
    shot: qq.shot,
    ru: qq.ru,
    uz: qq.uz,
  };
}
